#include<bits/stdc++.h>
using namespace std;
long long a[101],b[101];
long long exgcd(long long a,long long b,long long &x,long long &y)
{
    if(b==0)
    {
        x=1;
        y=0;
        return a;
    }
    long long g=exgcd(b,a%b,x,y);
    long long tx=x;
    x=y;
    y=tx-(a/b)*y;
    return g;
}
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld",&a[i],&b[i]);
    }
    long long sum=1;
    for(long long i=1;i<=n;i++)
    {
        sum*=a[i];
    }
    long long ans=0;
    for(long long i=1;i<=n;i++)
    {
        long long m=sum/a[i];
        long long x,y;
        exgcd(m,a[i],x,y);
        ans+=(__int128)m*x*b[i]%sum;
        ans%=sum;
    }
    printf("%lld",(ans%sum+sum)%sum);
    return 0;
}
